import java.util.Arrays

object Solution {
  /**
    * Disjoint Set Union (DSU) structure specialized for parity tracking.
    * For each element, it stores:
    * 1. parent: The parent in the set tree.
    * 2. parity: The parity (0 or 1) of the path weight from the node to its current parent.
    */
  class DSU(val n: Int) {
    val parent = Array.ofDim[Int](n)
    // parity[i] stores the parity of the path sum from node i to parent[i]
    val parity = Array.ofDim[Int](n) 

    init {
      for (i <- 0 until n) {
        parent(i) = i
        parity(i) = 0
      }
    }

    /**
      * Finds the representative (root) of the set containing node i, 
      * and updates the path parity along the way.
      * 
      * @param i The node to find the root for.
      * @return A pair: (root, path_parity_to_root).
      */
    def find(i: Int): (Int, Int) = {
      if (parent(i) == i) {
        (i, 0)
      } else {
        // Recursive call to find the root and parity of the parent
        val (root, parentParity) = find(parent(i))

        // Path compression: Make i point directly to the root
        parent(i) = root

        // Update parity: The new parity from i to root is (parity[i] + parentParity) % 2
        parity(i) = (parity(i) + parentParity) % 2

        (root, parity(i))
      }
    }

    /**
      * Tries to unite the sets containing nodes u and v, given the edge weight w.
      * 
      * If u and v are already in the same set, it checks if adding the edge 
      * creates a cycle with an odd total weight.
      * 
      * @param u Node u.
      * @param v Node v.
      * @param w Weight of the edge (0 or 1).
      * @return true if the edge is added (no conflict or successful union), false otherwise.
      */
    def union(u: Int, v: Int, w: Int): Boolean = {
      val (rootU, parityU) = find(u)
      val (rootV, parityV) = find(v)

      if (rootU != rootV) {
        // They are in different components, so we add the edge.
        // Merge V's set into U's set (arbitrary choice).
        parent(rootV) = rootU

        // We need to determine the new parity[rootV], which is the parity of 
        // the path from rootV to rootU.
        // Path: rootV --(parityV)--> v --(w)--> u --(parityU)--> rootU
        // The total parity difference between rootV and rootU must satisfy:
        // parity(rootV -> rootU) = parity(rootV -> v) + w + parity(u -> rootU)
        // Since parityU is (u -> rootU) and parityV is (v -> rootV), 
        // we need parity(rootV -> v) = parityV and parity(u -> rootU) = parityU.
        // The required parity from rootV to rootU is:
        // (parityV + w + parityU) % 2

        // Wait, the definition of parity[i] is path i -> parent[i].
        // We are setting parent[rootV] = rootU. We need parity[rootV] = (rootV -> rootU)
        // Path: rootV --(0)--> v --(w)--> u --(0)--> rootU (conceptual path through the tree structure)
        // Path from rootV to rootU: rootV -> v -> u -> rootU
        // Parity(rootV -> rootU) = Parity(rootV -> v) + w + Parity(u -> rootU)
        // Parity(rootV -> v) is the path from rootV to v *after* compression. But rootV is the root.
        // We know:
        // 1. Parity(v -> rootV) = parityV (which is 0 if rootV was the root, but generally it's path v->rootV)
        //    Wait, `find(v)` returns (rootV, parityV), where parityV is Path(v -> rootV).
        //    Thus, Parity(rootV -> v) = parityV.
        // 2. Parity(u -> rootU) = parityU.

        // Path Parity (rootV -> rootU) = Parity(rootV -> v) + w + Parity(u -> rootU)
        // Path Parity (rootV -> rootU) = parityV + w + parityU
        parity(rootV) = (parityV + w + parityU) % 2

        true // Edge added successfully
      } else {
        // u and v are already in the same component. Adding this edge creates a cycle.
        // The path weight between u and v through the existing tree edges is:
        // Cycle weight = Parity(u -> root) + w + Parity(v -> root)
        // Since Parity(u -> root) = parityU and Parity(v -> root) = parityV,
        // Cycle weight parity = (parityU + w + parityV) % 2.

        val cycleParity = (parityU + w + parityV) % 2

        // The condition is: "if adding this edge results in EVERY cycle having an even weight".
        // If the existing structure satisfies the property (all current cycles are even), 
        // adding an edge (u, v, w) creates a new cycle whose parity is cycleParity.
        // If cycleParity == 0 (even), the property is maintained.
        // If cycleParity == 1 (odd), the property is violated, and the edge is rejected.

        cycleParity == 0 // Return true if cycle parity is even (i.e., edge is accepted)
      }
    }
  }

  /**
   * The actual solution function wrapper, conforming to the required signature.
   * Note: The signature provided in the prompt uses Long for n and elements of edges,
   * suggesting large inputs, but standard competitive programming practice implies 
   * N and edge counts fit within Int for array indexing, while weights fit in Int.
   * We will treat N and edge counts as fitting within Int limits based on constraints (5*10^4), 
   * but match the requested Long types for the signature.
   */
  def solve(n_long: Long, edges_long: Array[Array[Long]]): Long = {
    val n = n_long.toInt

    // Convert Long arrays to Int arrays for processing, assuming values fit
    val edges = edges_long.map { arr =>
      Array(arr(0).toInt, arr(1).toInt, arr(2).toInt)
    }.toArray

    val dsu = new DSU(n)
    var addedEdgesCount = 0

    for (edge <- edges) {
      val u = edge(0)
      val v = edge(1)
      val w = edge(2).toInt

      // The union method returns true if the edge is added successfully
      if (dsu.union(u, v, w)) {
        addedEdgesCount += 1
      }
    }

    addedEdgesCount.toLong
  }
}
