class DSU(val n: Int) {
    val parent = Array.range(0, n).map(_ :: _).toArray // Initialize parent[i] = i
    // parity[i] stores the parity of the path from i to parent[i]
    // 0 means even weight path, 1 means odd weight path
    val parity = Array.fill(n)(0)

    /**
     * Finds the representative (root) of the set containing i,
     * and updates parity[i] to be the parity of the path from i to the root.
     * Returns a tuple: (root_id, parity_to_root)
     */
    def find(i: Int): (Int, Int) = {
        if (parent(i) == i) {
            (i, 0) // Root has 0 parity to itself
        } else {
            // Recursively find the root and parity of the parent
            val (root, parentParity) = find(parent(i))
            // Update parent[i] directly to the root (path compression)
            parent(i) = root
            // Update parity[i]: new_parity = old_parity(i->parent) + parity(parent->root) (mod 2)
            parity(i) = (parity(i) + parentParity) % 2
            (root, parity(i))
        }
    }

    /**
     * Unites the sets containing u and v, given the weight w of the edge (u, v).
     * Returns true if the union was performed (i.e., u and v were in different sets),
     * and false otherwise (i.e., adding the edge creates a cycle).
     *
     * If a cycle is formed, it checks the cycle condition:
     * Path_u_to_root + Edge_w + Path_v_to_root must be even (0 mod 2).
     *
     * @param u Node u
     * @param v Node v
     * @param w Weight of the edge (u, v) (0 or 1)
     * @return Boolean indicating if the edge was added (no cycle or cycle condition met).
     */
    def union(u: Int, v: Int, w: Int): Boolean = {
        val (rootU, parityU) = find(u)
        val (rootV, parityV) = find(v)

        if (rootU != rootV) {
            // Different sets: merge them.
            // Make rootV the parent of rootU.
            parent(rootU) = rootV

            // We need to set parity[rootU] such that the path from rootU to rootV has the required parity.
            // Path from u to v via edge (u,v) and paths to roots:
            // Parity(u -> rootU) + Parity(rootU -> rootV) + Parity(rootV -> v) = Parity(u -> v) (mod 2)
            // We know Parity(u -> v) = w (the edge weight).
            // We know Parity(u -> rootU) = parityU.
            // We know Parity(v -> rootV) = parityV.
            // We want to find Parity(rootU -> rootV) = P_new.
            // parityU + P_new + parityV = w (mod 2)
            // P_new = w - parityU - parityV (mod 2)
            // P_new = (w + parityU + parityV) mod 2

            parity(rootU) = (w + parityU + parityV) % 2
            return true // Edge added
        } else {
            // Same set: adding this edge creates a cycle.
            // Check the cycle condition: the sum of weights in the cycle must be even (0 mod 2).
            // Cycle path: u -> rootU -> v -> u
            // Weight sum = Parity(u -> rootU) + Parity(v -> rootV) + w (edge u-v)
            // Since rootU == rootV, the path from u to v through the tree is:
            // Parity(u -> rootU) XOR Parity(v -> rootU) = Parity(u -> v via tree)
            // The cycle parity = Parity(u -> v via tree) XOR w
            // Cycle parity = (parityU XOR parityV) XOR w

            val cycleParity = (parityU + parityV + w) % 2

            // The condition is: "every ring's edge weight sum remains even".
            // If we add the edge, the new cycle parity is 'cycleParity'.
            // We must maintain all cycles to have even weight, so we require cycleParity == 0.
            return cycleParity == 0
        }
    }
}

def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val nInt = n.toInt
    val dsu = new DSU(nInt)
    var addedEdgesCount = 0L

    for (edge in edges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        val w = edge(2).toInt

        // The union method returns true if the edge should be added (either no cycle, or cycle is even)
        val shouldAdd = dsu.union(u, v, w)

        if (shouldAdd) {
            addedEdgesCount += 1
        }
    }

    addedEdgesCount
}
