import scala.collection.mutable.ArrayBuffer

/**
 * Problem: Check if adding an edge maintains the property that all cycles have even total weight.
 * This is equivalent to checking if the graph remains bipartite with respect to the weights modulo 2.
 * Specifically, the condition "every cycle has an even total weight" is equivalent to saying that
 * for any two nodes u and v, all paths between them have the same path weight parity (modulo 2).
 *
 * This can be maintained using a Disjoint Set Union (DSU) structure augmented with parity information.
 * For each node i, we store d[i]: the parity of the path weight from node i to the representative of its set (parent[i]).
 *
 * When considering an edge (u, v) with weight w:
 * 1. Find representatives: root_u = find(u), root_v = find(v).
 * 2. If root_u == root_v:
 *    A cycle is formed. The path from u to v in the current graph has parity d[u] + d[v] (mod 2).
 *    The new edge has parity w.
 *    The cycle weight is (d[u] + d[v] + w) (mod 2).
 *    The edge is added ONLY if this cycle weight is 0 (even).
 *    Condition: (d[u] + d[v] + w) % 2 == 0.
 * 3. If root_u != root_v:
 *    The edge is added, merging the sets. The new path from root_v to root_u must be set.
 *    The path from u to v is w. The path from u to root_u is d[u]. The path from v to root_v is d[v].
 *    We set parent[root_v] = root_u.
 *    We need d[root_v] such that: d[root_v] + d[v] + w + d[u] == 0 (mod 2, path from root_v to root_u through v-u).
 *    A simpler way: The parity from root_v to root_u should be the parity of path (root_v -> v -> u -> root_u).
 *    Parity(root_v -> root_u) = Parity(root_v -> v) + Parity(v -> u) + Parity(u -> root_u)
 *                               = d[v] + w + d[u] (mod 2).
 */

object Solution {

    /**
     * DSU structure optimized for path parity tracking.
     * parent[i]: parent of node i.
     * parity[i]: parity of the path weight from node i to its current parent (parent[i]).
     */
    class DSU(n: Int) {
        val parent = Array.fill(n)(0)
        val parity = Array.fill(n)(0) // 0 or 1

        init {
            for (i <- 0 until n) {
                parent(i) = i
                parity(i) = 0
            }
        }

        /**
         * Finds the representative (root) of the set containing i,
         * and updates the parity[i] to be the parity of the path from i to the root.
         * Returns the root index.
         */
        def find(i: Int): (Int, Int) = {
            if (parent(i) == i) {
                (i, 0) // Root node, parity to itself is 0
            } else {
                val (root, parity_to_root_of_parent) = find(parent(i))
                // Path from i to root is: (i -> parent[i]) + (parent[i] -> root)
                // New parity[i] = old parity[i] + parity_to_root_of_parent (mod 2)
                parity(i) = (parity(i) + parity_to_root_of_parent) % 2
                parent(i) = root
                (root, parity(i))
            }
        }

        /**
         * Attempts to unite the sets containing u and v using the edge weight w.
         * Returns true if the edge is added (i.e., it maintains the even cycle property), false otherwise.
         */
        def union(u: Int, v: Int, w: Int): Boolean = {
            val (rootU, parityU) = find(u)
            val (rootV, parityV) = find(v)

            if (rootU == rootV) {
                // Cycle detection
                // Path u -> v in current graph has parity = parityU + parityV (mod 2)
                // New edge weight is w.
                // Cycle weight = (parityU + parityV + w) mod 2
                val cycleWeight = (parityU + parityV + w) % 2

                // Edge is added only if cycleWeight is 0 (even)
                if (cycleWeight == 0) {
                    true
                } else {
                    false // Fails the condition
                }
            } else {
                // Union: Merge rootV's set into rootU's set (arbitrarily)
                parent(rootV) = rootU

                // We need to set parity[rootV] such that the path from rootV to rootU has the correct parity.
                // Path: rootV -> v -> u -> rootU
                // Parity(rootV -> rootU) = Parity(rootV -> v) + Parity(v -> u) + Parity(u -> rootU)
                // Parity(rootV -> v) = parityV
                // Parity(v -> u) = w
                // Parity(u -> rootU) = parityU
                // Note: The path is from rootV to rootU.
                // Parity(rootV -> rootU) = parityV + w + parityU (mod 2)
                parity(rootV) = (parityV + w + parityU) % 2

                true // Edge is always added when roots are different
            }
        }
    }
}

